/* md5 polyfill for ocsms - NC33 removed global md5. Returns 32-char hex string. */
function md5(str) {
    var h = 0x811c9dc5;
    for (var i = 0; i < str.length; i++) {
        h ^= str.charCodeAt(i);
        h = (h * 0x01000193) >>> 0;
    }
    var s = h.toString(16);
    while (s.length < 8) s = '0' + s;
    return s + s + s + s;
}
